member.example:
Bind an EventTrigger command using a serialized binder field — the target EventTrigger is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private EventTriggerCommandBinder _pointerEnter;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnPointerEnter() { }
    }


Bind an EventTrigger command by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private EventTrigger _eventTrigger;
        
        private EventTriggerCommandBinder PointerEnter =>
            new(_eventTrigger, EventTriggerType.Enter);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnPointerEnter() { }
    }

Bind an EventTrigger command with one additional parameter by constructing the binder in code — subclass to provide the concrete type.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private EventTrigger _eventTrigger;
        
        private TaggedPointerEnterBinder PointerEnter =>
            new(_eventTrigger, EventTriggerType.Enter, "tag");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnPointerEnter(string tag) { }
    }

Bind an EventTrigger command with two additional parameters by constructing the binder in code — subclass to provide the concrete types.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private EventTrigger _target;
        
        private MyEventBinder EnterCommand =>
            new(_target, EventTriggerType.Enter, "tag", 1);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Enter(string tag, int priority) { }
    }

Bind an EventTrigger command with three additional parameters — subclass to provide the concrete types.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private EventTrigger _target;
        
        private MyEventBinder EnterCommand =>
            new( _target, EventTriggerType.Enter, "tag", 1, true);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Enter(string tag, int priority, bool active) { }
    }

Bind an EventTrigger command with four additional parameters — subclass to provide the concrete types.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private EventTrigger _target;
        
        private MyEventBinder EnterCommand =>
            new( _target, EventTriggerType.Enter, "tag", 1, true, 0.5f);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Enter(string tag, int priority, bool active, float weight) { }
    }
